mapper.select:
SELECT a.id, a.project_id AS "projectId", a.handover_type AS "handoverType", a.handover_time AS "handoverTime", a.handover_content AS "handoverContent", a.handover_user_id AS "handoverUserId", a.receiver_user_id AS "receiverUserId", a.handover_signature_url AS "handoverSignatureUrl", a.receiver_signature_url AS "receiverSignatureUrl", a.handover_signed_at AS "handoverSignedAt", a.receiver_signed_at AS "receiverSignedAt", a.attachment, a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", hu.name AS "handoverUserName", ru.name AS "receiverUserName", CASE a.handover_type WHEN 1 THEN '设计' WHEN 2 THEN '设计' WHEN 3 THEN '土建' ELSE '' END AS "from", CASE a.handover_type WHEN 1 THEN '土建' WHEN 2 THEN '精装' WHEN 3 THEN '精装' ELSE '' END AS "to", CASE a.handover_type WHEN 1 THEN '设计-土建交接' WHEN 2 THEN '设计-精装交接' WHEN 3 THEN '土建-精装交接' ELSE '' END AS "type", CASE WHEN a.receiver_signed_at IS NULL THEN 'pending' ELSE 'completed' END AS "status", CASE WHEN a.receiver_signed_at IS NULL THEN '待确认' ELSE '已完成' END AS "statusText" FROM project_handover a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account hu ON hu.id = a.handover_user_id LEFT JOIN sys_account ru ON ru.id = a.receiver_user_id
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.handover_type = #{params.handoverType} AND a.handover_time >= #{params.startDate} AND a.handover_time <= #{params.endDate}
AND a.handover_user_id = #{params.userId}
AND a.receiver_user_id = #{params.userId} AND a.receiver_signed_at IS NULL
AND a.receiver_signed_at IS NOT NULL
ORDER BY a.handover_time DESC, a.id DESC
